            <style type="text/css">

                .menu-kvartiry {

                }

                /* .hoverIGATION */
                .menu-kvartiry,
                .menu-kvartiry:after,
                .menu-kvartiry:before {
                  transition: all .5s;
                }
                .menu-kvartiry:hover {
                  color: #FFFFFF;  
                }


                /* stroke */
                .menu-kvartiry.stroke,
                .menu-kvartiry.fill {
                  position: relative;
                }
                .menu-kvartiry.stroke:after,
                .menu-kvartiry.fill:after {
                  position: absolute;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  margin: auto;
                  width: 0%;
                  content: '.';
                  color: transparent;
                  background: #F8A701;
                  height: 1px;
                }

                .menu-kvartiry.stroke:hover:after {
                  width: 100%;
                }

                .menu-kvartiry.fill {
                  transition: all 2s;
                }

                .menu-kvartiry.fill:after {
                  text-align: left;
                  content: '.';
                  margin: 0;
                  opacity: 0;
                }
                .menu-kvartiry.fill:hover {
                  color: #FFFFFF;
                  z-index: 1;
                }
                .menu-kvartiry.fill:hover:after {
                  z-index: -10;
                  animation: fill 1s forwards;
                  -webkit-animation: fill 1s forwards;
                  -moz-animation: fill 1s forwards;
                  opacity: 1;
                }

                /* Circle */
                .menu-kvartiry.circle {
                  position: relative;
                  overflow: hidden;
                  z-index: 1;
                }
                .menu-kvartiry.circle:after {
                  display: block;
                  position: absolute;
                  margin: 0;
                  top: 0;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  content: '.';
                  color: transparent;
                  width: 1px;
                  height: 1px;
                  border-radius: 50%;
                  background: transparent;
                }
                .menu-kvartiry.circle:hover:after {
                  -webkit-animation: circle 1.5s ease-in forwards;
                }

                /* SHIFT */
                .menu-kvartiry.shift {
                  position:relative;
                  z-index: 1;
                }
                .menu-kvartiry.shift:hover {
                  color: #FFFFFF;
                }
                .menu-kvartiry.shift:after {
                  display: block;
                  position: absolute;
                  top: 0;
                  left: 0;
                  bottom: 0;
                  right: 0;
                  margin: auto;
                  width: 100%;
                  height: 1px;
                  content: '.';
                  color: transparent;
                  background: #F8A701;
                  visibility: none;
                  opacity: 0;
                  z-index: -1;
                  border-radius: 12px;
                }
                .menu-kvartiry.shift:hover:after {
                  opacity: 1;
                  visibility: visible;
                  height: 100%;
                }



                /* Keyframes */
                @-webkit-keyframes fill {
                  0% {
                    width: 0%;
                    height: 1px;
                  }
                  50% {
                    width: 100%;
                    height: 1px;
                  }
                  100% {
                    width: 100%;
                    height: 100%;
                    background: #F8A701;
                  }
                }

                /* Keyframes */
                @-webkit-keyframes circle {
                  0% {
                    width: 1px;
                    top: 0;
                    left: 0;
                    bottom: 0;
                    right: 0;
                    margin: auto;
                    height: 1px;
                    z-index: -1;
                    background: #F8A701;
                    border-radius: 100%;
                  }
                  100% {
                    background: #F8A701;
                    height: 5000%;
                    width: 5000%;
                    z-index: -1;
                    top: 0;
                    bottom: 0;
                    left: 0;
                    right: 0;
                    margin: auto;
                    border-radius: 0;
                  }
                }

            </style>

        

            
